+        let (_tx, rx) = oneshot::channel::<Result<i32, JoinError>>();
+        let handle = TaskHandle::new(task_id, rx, std::sync::Weak::new());
+        let dbg = format!("{handle:?}");
+        assert!(dbg.contains("TaskHandle"));
